import{_ as i,o as l,c as o,a2 as a}from"./chunks/framework.CE5oItKu.js";const v=JSON.parse('{"title":"mango-file 集成 file-preview 方案","description":"","frontmatter":{},"headers":[],"relativePath":"mango-docs/designs/mango-file集成file-preview方案.md","filePath":"mango-docs/designs/mango-file集成file-preview方案.md"}'),d={name:"mango-docs/designs/mango-file集成file-preview方案.md"};function r(c,e,n,t,p,s){return l(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="mango-file-集成-file-preview-方案" tabindex="-1">mango-file 集成 file-preview 方案 <a class="header-anchor" href="#mango-file-集成-file-preview-方案" aria-label="Permalink to &quot;mango-file 集成 file-preview 方案&quot;">​</a></h1><p>更新时间：2026-05-24</p><h2 id="_1-目标" tabindex="-1">1. 目标 <a class="header-anchor" href="#_1-目标" aria-label="Permalink to &quot;1. 目标&quot;">​</a></h2><p>让业务方只持有并传递 <code>fileId</code>，通过 <code>mango-file</code> 完成文件权限、机构隔离、归档状态和下载能力校验；通过可配置预览地址把文件交给 <code>mango-file-preview</code> 或其它预览服务完成真实在线预览。</p><p>本方案解决：</p><ul><li>文件中心、模板、业务附件等场景可以按指定 <code>fileId</code> 打开在线预览。</li><li><code>mango-file</code> 预览地址配置支持绝对地址、相对地址、<code>fileId</code>、<code>fileUrl</code>、<code>fileName</code> 和安全相关基础参数。</li><li>前端复用 <code>FilePreviewPanel</code> 时不再自行拼 kkFileView 或第三方预览服务地址。</li><li>单体和微服务部署都能按相同语义访问预览能力。</li><li>业务数据继续只保存文件中心标识，不保存预览地址、下载地址或对象存储直连地址。</li></ul><h2 id="_2-范围" tabindex="-1">2. 范围 <a class="header-anchor" href="#_2-范围" aria-label="Permalink to &quot;2. 范围&quot;">​</a></h2><p>本次设计覆盖：</p><ul><li><code>mango-file</code> 预览元数据接口语义调整。</li><li><code>mango-file</code> 预览地址模板构建规则。</li><li><code>mango-file-preview</code> 基于 <code>fileId</code> 的预览入口、源文件临时访问令牌和预览引擎调用链。</li><li>单体部署与微服务部署的依赖和调用方式。</li><li>前端 <code>@mango/file</code> 预览组件接入方式。</li><li>权限、安全、生命周期、测试验收口径。</li></ul><p>不覆盖：</p><ul><li>Office 转 PDF、缩略图、OCR、在线编辑等派生产物持久化。</li><li>将 kkFileView 转换内核拆入 <code>mango-infra-tools-convert</code> 的实现。</li><li>业务模块批量迁移历史 URL 字段。</li></ul><h2 id="_3-现状判断" tabindex="-1">3. 现状判断 <a class="header-anchor" href="#_3-现状判断" aria-label="Permalink to &quot;3. 现状判断&quot;">​</a></h2><h3 id="_3-1-mango-file-现状" tabindex="-1">3.1 mango-file 现状 <a class="header-anchor" href="#_3-1-mango-file-现状" aria-label="Permalink to &quot;3.1 mango-file 现状&quot;">​</a></h3><p><code>mango-file</code> 已提供统一文件资产能力：</p><ul><li>上传、分片上传、秒传、下载、详情、分页、归档。</li><li>文件记录按机构隔离，归档文件不能通过普通详情、预览、下载访问。</li><li><code>FileApi.preview(Long id)</code> 返回 <code>FilePreviewVO</code>，当前主要包含文件元数据、登录态下载地址、对象存储直连或预签名地址。</li><li><code>FilePreviewVO.previewUrl</code> 当前默认等于 <code>/file/files/download?id=...</code> 或对象存储直连地址，适合图片、PDF、音视频等浏览器内置预览，不足以承载 Office、压缩包、邮件等复杂格式预览。</li></ul><h3 id="_3-2-mango-file-preview-现状" tabindex="-1">3.2 mango-file-preview 现状 <a class="header-anchor" href="#_3-2-mango-file-preview-现状" aria-label="Permalink to &quot;3.2 mango-file-preview 现状&quot;">​</a></h3><p><code>mango-file-preview</code> 已是独立平台模块：</p><ul><li><code>mango-file-preview-api</code> 提供 <code>FilePreviewApi.preview(Long fileId)</code>。</li><li><code>mango-file-preview-core</code> 依赖 <code>mango-file-api</code>，通过 <code>FileApi.get(fileId)</code> 校验文件可见性，通过 <code>FileApi.download(fileId)</code> 读取源文件。</li><li><code>mango-file-preview-starter</code> 暴露： <ul><li><code>GET /file-preview/files/preview-link?fileId=...</code></li><li><code>GET /file-preview/files/preview?fileId=...</code></li><li><code>GET /file-preview/sources/{token}</code></li></ul></li><li>预览源文件令牌保存在当前进程内存，令牌携带创建时的 <code>MangoContextSnapshot</code>，预览引擎回读源文件时恢复上下文后再调用 <code>FileApi.download</code>。</li><li>单体应用已同时装配 <code>mango-file-starter</code> 与 <code>mango-file-preview-starter</code>；微服务 <code>mango-file-preview-app</code> 已通过 <code>mango-file-starter-remote</code> 调用文件服务。</li></ul><h2 id="_4-核心决策" tabindex="-1">4. 核心决策 <a class="header-anchor" href="#_4-核心决策" aria-label="Permalink to &quot;4. 核心决策&quot;">​</a></h2><h3 id="_4-1-依赖方向" tabindex="-1">4.1 依赖方向 <a class="header-anchor" href="#_4-1-依赖方向" aria-label="Permalink to &quot;4.1 依赖方向&quot;">​</a></h3><p>采用单向依赖：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>业务前端/业务服务 -&gt; mango-file</span></span>
<span class="line"><span>前端预览入口 -&gt; mango-file-preview</span></span>
<span class="line"><span>mango-file-preview -&gt; mango-file-api</span></span></code></pre></div><p><code>mango-file</code> 不编译依赖 <code>mango-file-preview-api</code>，避免文件资产模块反向依赖预览适配模块。<code>mango-file</code> 只负责给出运行时预览入口地址；<code>mango-file-preview</code> 负责把 <code>fileId</code> 转为预览引擎可消费的源文件 URL。</p><h3 id="_4-2-预览入口归一" tabindex="-1">4.2 预览入口归一 <a class="header-anchor" href="#_4-2-预览入口归一" aria-label="Permalink to &quot;4.2 预览入口归一&quot;">​</a></h3><p><code>mango-file</code> 的 <code>GET /file/files/preview?id=...</code> 继续作为业务统一查询入口。返回值保持 <code>FilePreviewVO</code>，但语义调整为：</p><ul><li>浏览器原生支持类型：<code>previewUrl</code> 优先返回可直接嵌入的源文件访问地址。</li><li>复杂格式：<code>previewUrl</code> 按 <code>previewProviderUrl</code> 构建，默认返回 <code>/file-preview/files/preview?fileId={id}&amp;fileUrl=...&amp;fileName=...&amp;expireSeconds=...</code>。</li><li><code>downloadUrl</code> 始终表达下载入口。</li><li><code>directPreviewUrl</code>、<code>directDownloadUrl</code> 只表达对象存储直连或预签名 URL，不用于复杂格式预览服务入口。</li></ul><p>前端只消费 <code>FilePreviewVO.previewUrl</code>、<code>downloadUrl</code>、<code>direct*</code> 字段，不再根据扩展名自行拼 <code>VITE_FILE_PREVIEW_PROVIDER_URL</code>。</p><h3 id="_4-3-file-preview-只接收-fileid" tabindex="-1">4.3 file-preview 只接收 fileId <a class="header-anchor" href="#_4-3-file-preview-只接收-fileid" aria-label="Permalink to &quot;4.3 file-preview 只接收 fileId&quot;">​</a></h3><p><code>mango-file-preview</code> 对外只接收 <code>fileId</code>，不接收业务 URL、对象存储 URL、下载 URL 或任意外链。源文件访问只由内部令牌接口提供：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /file-preview/files/preview?fileId={fileId}</span></span>
<span class="line"><span>  -&gt; 生成 source token</span></span>
<span class="line"><span>  -&gt; 拼 /file-preview/sources/{token}?fullfilename=...</span></span>
<span class="line"><span>  -&gt; base64 后交给 /onlinePreview</span></span></code></pre></div><p>这样可以保证预览链路复用 <code>mango-file</code> 的权限、机构、归档状态和存储适配能力。</p><h2 id="_5-模块设计" tabindex="-1">5. 模块设计 <a class="header-anchor" href="#_5-模块设计" aria-label="Permalink to &quot;5. 模块设计&quot;">​</a></h2><h3 id="_5-1-mango-file" tabindex="-1">5.1 mango-file <a class="header-anchor" href="#_5-1-mango-file" aria-label="Permalink to &quot;5.1 mango-file&quot;">​</a></h3><p>保留职责：</p><ul><li>文件记录、物理对象、逻辑目录、上传下载、归档、机构隔离。</li><li>判断文件是否可预览。</li><li>返回运行时预览入口和下载入口。</li></ul><p>需要调整：</p><ul><li>增加 <code>mango.file.preview.provider-url</code> 的标准默认值，默认为 <code>/file-preview/files/preview</code>。</li><li><code>FileServiceImpl.preview(id)</code> 在复杂格式时，将 <code>previewUrl</code> 设置为按 <code>previewProviderUrl</code> 构建出的预览地址。</li><li><code>previewProviderUrl</code> 没有占位符时，自动追加 <code>fileId</code>、<code>fileUrl</code>、<code>fileName</code>、<code>expireSeconds</code> 参数。</li><li><code>previewProviderUrl</code> 有占位符时，支持 <code>{fileId}</code>、<code>{fileUrl}</code>、<code>{fileName}</code>、<code>{expireSeconds}</code> 原位替换。</li><li><code>FileRecordVO</code> 的列表/详情仍可返回下载或直连地址，但复杂格式最终预览以 <code>FilePreviewVO.previewUrl</code> 为准，避免列表接口过早生成预览令牌或复杂入口。</li><li><code>previewProviderUrl</code> 支持相对路径和绝对路径： <ul><li>单体：<code>/file-preview/files/preview</code></li><li>网关：<code>/api/file-preview/files/preview</code></li><li>独立域名：<code>https://preview.example.com/file-preview/files/preview</code></li><li>URL 模板：<code>https://preview.example.com/onlinePreview?url={fileUrl}&amp;name={fileName}</code></li></ul></li></ul><p>不新增数据库表。现有 <code>file_settings.preview_provider_url</code>、<code>preview_expire_seconds</code>、<code>preview_external_extensions</code> 可继续承载运行时配置。</p><h3 id="_5-2-mango-file-preview" tabindex="-1">5.2 mango-file-preview <a class="header-anchor" href="#_5-2-mango-file-preview" aria-label="Permalink to &quot;5.2 mango-file-preview&quot;">​</a></h3><p>保留职责：</p><ul><li>接收 <code>fileId</code>。</li><li>调用 <code>FileApi.get</code> 校验文件可见性并获取文件名、类型、大小。</li><li>生成源文件临时访问令牌。</li><li>调用预览引擎并返回预览页面。</li><li>通过 <code>FileApi.download</code> 读取源文件流。</li></ul><p>需要增强：</p><ul><li><code>FilePreviewProperties</code> 增加外部访问基准地址配置，例如 <code>publicBaseUrl</code>，用于微服务或网关场景下生成预览引擎可回调的源文件绝对地址。</li><li>源文件 token 使用 <code>mango-infra-kv</code> 存储，支持多实例部署和重启后令牌失效语义可控。</li><li><code>preview-link</code> 与 <code>preview</code> 两个接口保持： <ul><li><code>preview-link</code> 返回给 API 调用方。</li><li><code>preview</code> 用于 iframe 或新窗口直接打开。</li></ul></li><li>令牌只保存 <code>fileId</code>、上下文快照、过期时间，不保存下载 URL 或文件内容。</li></ul><h3 id="_5-3-前端-mango-file" tabindex="-1">5.3 前端 @mango/file <a class="header-anchor" href="#_5-3-前端-mango-file" aria-label="Permalink to &quot;5.3 前端 @mango/file&quot;">​</a></h3><p>调整方向：</p><ul><li><code>FilePreviewPanel</code> 加载 <code>fileApi.preview(fileId)</code>。</li><li>图片、PDF、音视频仍以内联方式渲染。</li><li>复杂格式直接 iframe <code>preview.previewUrl</code>，不再由前端重新拼预览服务地址。</li><li><code>previewProviderUrl</code> 只作为历史兼容兜底，默认预览地址由后端生成。</li><li>下载继续调用 <code>downloadFileRecord</code>，优先使用 <code>directDownloadUrl</code>，否则走 <code>/file/files/download</code>。</li></ul><p>前端组件只关心“预览地址是否可嵌入”，不关心 kkFileView、LibreOffice、对象存储或源文件令牌细节。</p><h2 id="_6-调用链" tabindex="-1">6. 调用链 <a class="header-anchor" href="#_6-调用链" aria-label="Permalink to &quot;6. 调用链&quot;">​</a></h2><h3 id="_6-1-单体部署" tabindex="-1">6.1 单体部署 <a class="header-anchor" href="#_6-1-单体部署" aria-label="Permalink to &quot;6.1 单体部署&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser</span></span>
<span class="line"><span>  -&gt; GET /file/files/preview?id=100</span></span>
<span class="line"><span>  -&gt; mango-file 校验文件并返回 previewUrl=/file-preview/files/preview?fileId=100</span></span>
<span class="line"><span>  -&gt; iframe GET /file-preview/files/preview?fileId=100</span></span>
<span class="line"><span>  -&gt; mango-file-preview 本地调用 FileApi.get</span></span>
<span class="line"><span>  -&gt; 生成 source token</span></span>
<span class="line"><span>  -&gt; forward /onlinePreview?url=base64(sourceUrl)</span></span>
<span class="line"><span>  -&gt; 预览引擎 GET /file-preview/sources/{token}</span></span>
<span class="line"><span>  -&gt; mango-file-preview 本地调用 FileApi.download</span></span></code></pre></div><h3 id="_6-2-微服务部署" tabindex="-1">6.2 微服务部署 <a class="header-anchor" href="#_6-2-微服务部署" aria-label="Permalink to &quot;6.2 微服务部署&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser</span></span>
<span class="line"><span>  -&gt; Gateway /file/files/preview?id=100</span></span>
<span class="line"><span>  -&gt; mango-file-app 返回 previewUrl=/file-preview/files/preview?fileId=100</span></span>
<span class="line"><span>  -&gt; Browser/Gateway 访问 mango-file-preview-app</span></span>
<span class="line"><span>  -&gt; mango-file-preview-app 通过 mango-file-starter-remote 调 FileApi.get/download</span></span>
<span class="line"><span>  -&gt; 预览引擎回调 publicBaseUrl + /file-preview/sources/{token}</span></span></code></pre></div><p>微服务部署必须保证预览引擎能访问 <code>sourceUrl</code>。如果预览引擎与服务端同进程，<code>publicBaseUrl</code> 可以走本服务外部地址；如果预览引擎独立进程，必须配置它可访问的网关或服务地址。</p><h2 id="_7-接口变化" tabindex="-1">7. 接口变化 <a class="header-anchor" href="#_7-接口变化" aria-label="Permalink to &quot;7. 接口变化&quot;">​</a></h2><h3 id="_7-1-保持兼容的接口" tabindex="-1">7.1 保持兼容的接口 <a class="header-anchor" href="#_7-1-保持兼容的接口" aria-label="Permalink to &quot;7.1 保持兼容的接口&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /file/files/preview?id={id}</span></span>
<span class="line"><span>GET /file-preview/files/preview-link?fileId={id}</span></span>
<span class="line"><span>GET /file-preview/files/preview?fileId={id}</span></span>
<span class="line"><span>GET /file-preview/sources/{token}</span></span></code></pre></div><h3 id="_7-2-filepreviewvo-字段语义" tabindex="-1">7.2 FilePreviewVO 字段语义 <a class="header-anchor" href="#_7-2-filepreviewvo-字段语义" aria-label="Permalink to &quot;7.2 FilePreviewVO 字段语义&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>语义</th></tr></thead><tbody><tr><td><code>id</code></td><td>文件 ID</td></tr><tr><td><code>fileName</code></td><td>原始文件名</td></tr><tr><td><code>fileExt</code></td><td>扩展名</td></tr><tr><td><code>fileSize</code></td><td>文件大小</td></tr><tr><td><code>contentType</code></td><td>内容类型</td></tr><tr><td><code>previewable</code></td><td>当前文件是否有可用预览路径</td></tr><tr><td><code>previewUrl</code></td><td>前端打开预览的入口。可能是文件下载地址、对象存储直连地址，或由 <code>previewProviderUrl</code> 构建出的预览服务地址</td></tr><tr><td><code>downloadUrl</code></td><td>下载入口</td></tr><tr><td><code>directAccess</code></td><td>是否存在对象存储直连能力</td></tr><tr><td><code>directPreviewUrl</code></td><td>对象存储直连预览地址，只用于源文件直连</td></tr><tr><td><code>directDownloadUrl</code></td><td>对象存储直连下载地址</td></tr><tr><td><code>directPreviewExpireSeconds</code></td><td>直连预览地址有效期</td></tr><tr><td><code>directDownloadExpireSeconds</code></td><td>直连下载地址有效期</td></tr></tbody></table><p>不新增 <code>previewType</code> 字段。前端可根据文件类型和 <code>previewUrl</code> 渲染方式判断内联或 iframe。</p><h2 id="_8-数据变化" tabindex="-1">8. 数据变化 <a class="header-anchor" href="#_8-数据变化" aria-label="Permalink to &quot;8. 数据变化&quot;">​</a></h2><p>不新增表，不新增 migration。</p><p>复用 <code>file_settings</code>：</p><ul><li><code>preview_provider_url</code>：复杂格式预览入口。</li><li><code>preview_expire_seconds</code>：直连预览和预览源文件令牌有效期的默认参考值。</li><li><code>preview_external_extensions</code>：复杂格式扩展名集合。</li></ul><p>建议安装默认值：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>preview_provider_url=/file-preview/files/preview</span></span>
<span class="line"><span>preview_external_extensions=doc,docx,xls,xlsx,xlsm,ppt,pptx,odt,ods,odp,ofd,wps,et,dps,csv,txt,zip,rar,7z,eml,msg</span></span></code></pre></div><p>历史环境如未配置 <code>preview_provider_url</code>，复杂格式继续返回下载入口，前端显示“下载查看”。</p><h2 id="_9-安全与生命周期" tabindex="-1">9. 安全与生命周期 <a class="header-anchor" href="#_9-安全与生命周期" aria-label="Permalink to &quot;9. 安全与生命周期&quot;">​</a></h2><ul><li>所有业务文件仍由 <code>mango-file</code> 校验机构、归档状态和访问权限。</li><li><code>mango-file-preview</code> 的 <code>preview</code>、<code>preview-link</code> 使用 <code>file:files:query</code> 权限。</li><li><code>sources/{token}</code> 是临时令牌接口，只供预览引擎读取源文件；令牌过期后必须拒绝访问。</li><li>源文件 token 不允许出现在业务表、业务扩展字段或长期缓存中。</li><li><code>FilePreviewVO.previewUrl</code> 是运行时派生地址，业务模块不能持久化。</li><li>iframe 预览路径需要允许同源嵌入；当前 <code>FilePreviewFrameOptionsFilter</code> 保持对 <code>/file-preview/</code> 和 <code>/onlinePreview</code> 设置 <code>SAMEORIGIN</code>。</li><li>对象存储预签名 URL 只用于浏览器源文件直连，不作为复杂文档预览的跨模块契约。</li></ul><h2 id="_10-失败策略" tabindex="-1">10. 失败策略 <a class="header-anchor" href="#_10-失败策略" aria-label="Permalink to &quot;10. 失败策略&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>行为</th></tr></thead><tbody><tr><td>文件不存在、跨机构、已归档</td><td><code>mango-file</code> 或 <code>mango-file-preview</code> 返回业务失败</td></tr><tr><td>未配置 <code>preview_provider_url</code></td><td>复杂格式回退为下载查看</td></tr><tr><td>预览源 token 过期</td><td><code>sources/{token}</code> 返回令牌无效</td></tr><tr><td>预览引擎转换失败</td><td>保持引擎错误页或错误响应，前端提供下载</td></tr><tr><td><code>mango-file-preview</code> 服务不可用</td><td><code>previewUrl</code> 可生成但打开失败，前端保留下载动作</td></tr><tr><td>多实例 token 丢失</td><td>source token 必须使用 KV 存储并设置 TTL，不能继续依赖进程内 Map</td></tr></tbody></table><h2 id="_11-实施步骤" tabindex="-1">11. 实施步骤 <a class="header-anchor" href="#_11-实施步骤" aria-label="Permalink to &quot;11. 实施步骤&quot;">​</a></h2><p>本方案一次性交付完整能力，不按阶段交付半成品。实施时按以下步骤推进，每一步完成后继续下一步，最终统一验收。</p><h3 id="_11-1-统一预览入口" tabindex="-1">11.1 统一预览入口 <a class="header-anchor" href="#_11-1-统一预览入口" aria-label="Permalink to &quot;11.1 统一预览入口&quot;">​</a></h3><ul><li>调整 <code>mango-file</code> 的复杂格式 <code>previewUrl</code> 生成逻辑。</li><li>将默认 <code>preview_provider_url</code> 配置为 <code>/file-preview/files/preview</code>。</li><li>调整 <code>FilePreviewPanel</code>，复杂格式直接使用后端返回的 <code>previewUrl</code>。</li><li>补充 <code>mango-file-preview-app</code> E2E，覆盖 <code>fileId -&gt; preview -&gt; source -&gt; engine</code> 链路。</li></ul><h3 id="_11-2-完成部署稳态" tabindex="-1">11.2 完成部署稳态 <a class="header-anchor" href="#_11-2-完成部署稳态" aria-label="Permalink to &quot;11.2 完成部署稳态&quot;">​</a></h3><ul><li><code>mango-file-preview</code> 增加 <code>publicBaseUrl</code>。</li><li>将 source token 存储从本地 Map 切换到 <code>mango-infra-kv</code>，过期时间使用 TTL。</li><li>增加多实例部署说明和配置样例。</li></ul><h3 id="_11-3-接入派生产物能力" tabindex="-1">11.3 接入派生产物能力 <a class="header-anchor" href="#_11-3-接入派生产物能力" aria-label="Permalink to &quot;11.3 接入派生产物能力&quot;">​</a></h3><ul><li>与 <code>mango-infra-tools-convert</code> 或文档转换模块对接。</li><li><code>mango-file</code> 负责保存原文件和预览产物关系。</li><li>对高成本格式支持异步转换、缓存、重试和失败状态。</li></ul><h2 id="_12-验收标准" tabindex="-1">12. 验收标准 <a class="header-anchor" href="#_12-验收标准" aria-label="Permalink to &quot;12. 验收标准&quot;">​</a></h2><ul><li>上传 <code>txt/docx/pdf/png/mp4</code> 等文件后，文件中心可以通过 <code>fileId</code> 打开预览或下载。</li><li><code>GET /file/files/preview?id=...</code> 对复杂格式返回 <code>/file-preview/files/preview?fileId=...</code> 风格的预览入口。</li><li>前端 <code>FilePreviewPanel</code> 不需要配置第三方 provider URL 即可打开复杂格式预览入口。</li><li><code>mango-file-preview</code> 只能通过 <code>fileId</code> 获取源文件，不能接收任意外部 URL。</li><li>已归档文件、跨机构文件不能预览。</li><li>单体应用和 <code>mango-file-preview-app</code> 微服务形态均有验证命令或测试记录。</li></ul><h2 id="_13-预期验证方式" tabindex="-1">13. 预期验证方式 <a class="header-anchor" href="#_13-预期验证方式" aria-label="Permalink to &quot;13. 预期验证方式&quot;">​</a></h2><ul><li>后端单元/集成： <ul><li><code>mvn -pl mango/mango-platform/mango-file/mango-file-core test</code></li><li><code>mvn -pl mango/mango-app/microservice/mango-file-preview-app test</code></li></ul></li><li>后端质量： <ul><li><code>mvn -pl mango/mango-platform/mango-file-preview,mango/mango-platform/mango-file -am mango:check -Drule=all</code></li></ul></li><li>前端： <ul><li><code>pnpm --dir mango-ui test</code></li><li><code>pnpm --dir mango-ui lint</code></li></ul></li><li>手工验收： <ul><li>文件中心上传复杂格式文件。</li><li>打开详情预览面板。</li><li>确认 iframe 访问 <code>/file-preview/files/preview?fileId=...</code>。</li><li>确认下载按钮仍可用。</li></ul></li></ul><h2 id="_14-风险" tabindex="-1">14. 风险 <a class="header-anchor" href="#_14-风险" aria-label="Permalink to &quot;14. 风险&quot;">​</a></h2><ul><li>当前 source token 是进程内存，微服务多实例下预览引擎回调如果落到不同实例会失败。</li><li><code>FileFeignClient.downloadResponse</code> 当前以 <code>byte[]</code> 接收远程下载，大文件预览会占用内存；微服务预览链路需要改为流式 Feign 或优先使用对象存储后端读取能力。</li><li><code>mango-file</code> README 中存在由 render/convert 负责复杂转换的描述，需要在实现时区分“在线预览入口”和“派生产物转换”。</li><li>预览引擎依赖 LibreOffice/字体/系统库，不同部署环境的格式支持范围可能不同。</li></ul>`,84)])])}const h=i(d,[["render",r]]);export{v as __pageData,h as default};
